package cli

import (
	"fmt"
	"sort"
	"strings"

	"github.com/mvanhorn/printing-press-library/library/travel/roadside-america/internal/roadside"
	"github.com/spf13/cobra"
)

type countEntry struct {
	Key   string `json:"key"`
	Count int    `json:"count"`
}

type statsView struct {
	Source     string       `json:"source"`
	Total      int          `json:"total"`
	ByState    []countEntry `json:"by_state"`
	ByCategory []countEntry `json:"by_category"`
	Note       string       `json:"note,omitempty"`
}

func newNovelStatsCmd(flags *rootFlags) *cobra.Command {
	cmd := &cobra.Command{
		Use:   "stats",
		Short: "Summarize the local cache: counts by state and by category, plus totals.",
		Long: strings.Trim(`
Summarize the local attraction cache: total cached attractions, counts by state,
and counts by local category. Operates entirely offline over data already
fetched by 'state', 'near', or 'show'.`, "\n"),
		Example: strings.Trim(`
  roadside-america-pp-cli stats
  roadside-america-pp-cli stats --agent`, "\n"),
		Annotations: map[string]string{"mcp:read-only": "true"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if dryRunOK(flags) {
				fmt.Fprintln(cmd.OutOrStdout(), "would summarize the local attraction cache")
				return nil
			}
			ctx := cmd.Context()
			s, err := openRoadsideStore(ctx)
			if err != nil {
				return err
			}
			defer s.Close()
			all, err := loadCachedAttractions(s, 0)
			if err != nil {
				return err
			}

			stateCounts := map[string]int{}
			catCounts := map[string]int{}
			for _, a := range all {
				if a.State != "" {
					stateCounts[strings.ToUpper(a.State)]++
				}
				for _, c := range roadside.Classify(a) {
					catCounts[c]++
				}
			}

			byState := make([]countEntry, 0, len(stateCounts))
			for k, v := range stateCounts {
				byState = append(byState, countEntry{Key: k, Count: v})
			}
			sort.Slice(byState, func(i, j int) bool {
				if byState[i].Count != byState[j].Count {
					return byState[i].Count > byState[j].Count
				}
				return byState[i].Key < byState[j].Key
			})

			byCategory := make([]countEntry, 0, len(catCounts))
			for _, name := range roadside.CategoryNames() {
				if v, ok := catCounts[name]; ok {
					byCategory = append(byCategory, countEntry{Key: name, Count: v})
				}
			}

			view := statsView{
				Source:     roadside.SourceLabel,
				Total:      len(all),
				ByState:    byState,
				ByCategory: byCategory,
			}
			if len(all) == 0 {
				view.Note = "Local cache is empty. Run 'state <ST>' or 'near <place>' to populate it."
			}

			if machineOutput(cmd, flags) {
				return flags.printJSON(cmd, view)
			}
			w := cmd.OutOrStdout()
			fmt.Fprintf(w, "%s\n", bold(fmt.Sprintf("%d attractions cached", view.Total)))
			if view.Note != "" {
				fmt.Fprintf(w, "%s\n", view.Note)
				return nil
			}
			fmt.Fprintln(w, "\nBy state:")
			tw := newTabWriter(w)
			for _, e := range view.ByState {
				fmt.Fprintf(tw, "  %s\t%d\n", e.Key, e.Count)
			}
			tw.Flush()
			fmt.Fprintln(w, "\nBy category:")
			tw2 := newTabWriter(w)
			for _, e := range view.ByCategory {
				fmt.Fprintf(tw2, "  %s\t%d\n", e.Key, e.Count)
			}
			tw2.Flush()
			return nil
		},
	}
	return cmd
}
